import{_ as a,o as t,c as i,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Link Configuration FAQ","description":"","frontmatter":{"title":"Link Configuration FAQ","slug":"link-configuration-faq"},"headers":[],"relativePath":"account-hub/link-configuration-faq.md","filePath":"account-hub/link-configuration-faq.md"}'),n={name:"account-hub/link-configuration-faq.md"};function r(s,e,l,p,h,d){return t(),i("div",null,[...e[0]||(e[0]=[o('<p>The most frequently asked questions about link configuration.</p><details><summary>Why are Branch deep links redirecting to Desktop Fallbacks on iPad?</summary><p>Apple treats iPad as a desktop device. This means all links by default will redirect as if on a Desktop device. Using this guide, <a href="./configure-default-link-behaviors.html#i-pad-redirect-link-behavior">add custom fallback for iPad devices</a>.</p></details><details><summary>Can I have multiple custom domains for one app?</summary><p>You can have unlimited custom domains if you have <a href="https://branch.io/pricing" target="_blank" rel="noreferrer">Branch Activation</a>.</p><p>Check out our <a href="https://help.branch.io/docs/add-multiple-custom-domains" target="_blank" rel="noreferrer">Add Multiple Custom Domains</a> release note for more information.</p></details><details><summary>Why does the link redirect to fallback\\_url even when the app is already installed when the link is clicked from Chrome/Gmail?</summary><p>This usually happens when the Android URI scheme set on the dashboard does not match with the one in the Android Manifest file.</p></details><details><summary>How do Branch Links handle redirecting users into the App Store or Google Play store?</summary><p>Best practice is to find the app via the Google Play/App Store search functionality, as this provides us with all the info needed to identify the specific app that should be used for redirection. This includes the package name for Android and the App Store ID for iOS.</p><p>This is generally a better experience than using an HTTPS URL to redirect users to the page in the app store--while this can still open the app, it risks opening the page in a browser instead of opening the App Store or Google Play app. With the package name or App Store ID, Branch Links can automatically open the appropriate store app and page using the market:// URI scheme, along with the package name or the itms-app:// URI, with no risk of this opening in the browser.</p><p>While there are other identifiers (such as a deep link URI scheme) that can be used to identify apps, these aren&#39;t necessarily unique to a single app in the App Store or Google Play store, so these aren&#39;t factored in when routing users who don&#39;t have the app, as the information mentioned above will ensure we&#39;re routing them to the right place.</p><p>In absence of the above information (i.e. if no package name or App Store ID can be provided), a direct URL can be used, and we&#39;ll redirect a user normally in-browser for cases like these.</p></details><details><summary>How do I set up an iPad redirect to my website?</summary><p>When clicking on a Branch Link from an iPad, users are being redirected to the website and not the App Store. With the release of OS 13+, the iPad is now reporting as a desktop because Apple is sending the user agent as macOS. You can do one of two things to resolve the issue:</p><ol><li>Set an <code>$ipad_url</code> on the link-level</li><li>Or, set the iPad fallback in the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">Advanced Mobile Redirects</a> section of link settings in the Branch dashboard to the iTunes link for your app.</li></ol></details><details><summary>When configuring my redirects I cannot find my app from the list of apps, what do I do?</summary><p>If you are unable to find your app using the App search field on the Branch Dashboard Configuration page. Please select &#39;Custom URL &#39;and enter the link to the Playstore or AppStore for your app.<br> This will not impact functionality in any way.</p><p>If you are unable to find your app using the App Search field on the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">Configuration</a> page, you can do the following:</p><ol><li>Select the option <strong>I have an Android/iOS App</strong>.</li><li>Select <strong>Custom URL</strong> and enter in the link to your app, and provide the Android Playstore Package Name and/or Apple App Store ID.</li></ol><p><em>[Image: 1784]**[Image: 1782]</em></p></details>',7)])])}const f=a(n,[["render",r]]);export{u as __pageData,f as default};
